Something weird must be happening in Qt internals because in this tiny example, the missing copy constructor gets caught at compile time rather than causing a crash at run time:

```c++
#include <functional>

#include <pybind11/pybind11.h>
#include <pybind11/functional.h>

namespace py = pybind11;

class UncopyableClass {
    UncopyableClass(const UncopyableClass &);
    UncopyableClass &operator=(const UncopyableClass &);
public:
    UncopyableClass() {}
};

PYBIND11_PLUGIN(example) {
    py::module m("example", "pybind11 bug exaple");

    // Uncopyable class can still be instantiated from python
    py::class_<UncopyableClass> UncopyableClass_class(m, "UncopyableClass");
    UncopyableClass_class.def(py::init<>());

    // This will fail on compile
    m.def("send_uncopyable", [](std::function<void(UncopyableClass)> cb) {
        UncopyableClass uncopyable;
        cb(uncopyable);
    });

    return m.ptr();
}
```

Will also work fine if I pass through an `UncopyableClass *` instead! So perhaps there may be something I can do to get this to work.

